@app.route("/callback")
def callback():
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        logger.warning("OIDC error response: %s - %s", error, error_description)
        return jsonify({"error": "Authentication failed"}), 403

    code = request.args.get("code")
    state = request.args.get("state")

    if not code or not state:
        logger.warning("Missing code or state in callback")
        abort(400)

    pending_states = session.get("pending_states", {})
    state_data = pending_states.pop(state, None)
    session["pending_states"] = pending_states

    if not state_data:
        logger.warning("Invalid or expired state parameter")
        abort(403)

    if time.time() - state_data.get("created_at", 0) > STATE_EXPIRY_SECONDS:
        logger.warning("State parameter expired")
        abort(403)

    expected_nonce = state_data["nonce"]

    config = _get_oidc_configuration()

    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": OIDC_REDIRECT_URI,
        "client_id": OIDC_CLIENT_ID,
        "client_secret": OIDC_CLIENT_SECRET,
    }

    try:
        token_response = requests.post(
            config["token_endpoint"],
            data=token_data,
            timeout=10,
        )
        token_response.raise_for_status()
        token_json = token_response.json()
    except requests.RequestException as e:
        logger.error("Token exchange failed: %s", e)
        return jsonify({"error": "Authentication failed"}), 500

    id_token_raw = token_json.get("id_token")
    if not id_token_raw:
        logger.error("No id_token in token response")
        return jsonify({"error": "Authentication failed"}), 500

    claims = _validate_id_token(id_token_raw, expected_nonce)
    if not claims:
        logger.warning("ID token validation failed")
        return jsonify({"error": "Authentication failed"}), 403

    session.clear()
    session.permanent = True
    session["user"] = {
        "sub": claims.get("sub"),
        "email": claims.get("email"),
        "name": claims.get("name"),
        "authenticated_at": time.time(),
    }

    login_redirect = session.pop("login_redirect", "/")
    if login_redirect not in ALLOWED_REDIRECT_PATHS:
        login_redirect = "/"

    logger.info("User authenticated: sub=%s", claims.get("sub"))
    return redirect(login_redirect)


